constexpr const country_entry* find_by_alpha2(std::string_view code) noexcept {
    const auto compact = pack_alpha2_compact(code);
    if (!compact) return nullptr;
    const auto row = alpha2_to_row[*compact];
    return row == missing_code ? nullptr : &countries[row];
}

constexpr const country_entry* find_by_alpha3(std::string_view code) noexcept {
    const auto packed = pack_alpha3(code);
    if (!packed) return nullptr;
    const auto row = alpha3_to_row[*packed];
    return row == missing_code ? nullptr : &countries[row];
}

constexpr const country_entry* find_by_country_code(std::uint16_t code) noexcept {
    if (code >= country_code_to_row.size()) return nullptr;
    const auto row = country_code_to_row[code];
    return row == missing_code ? nullptr : &countries[row];
}

inline std::string iso_3166_2_code(const country_entry& entry) {
    return std::string("ISO 3166-2:") + unpack_alpha2(entry.alpha2);
}

inline constexpr std::size_t country_count = countries.size();

